function FI({children,delay=0}){const[v,setV]=useState(false);useEffect(()=>{const t=setTimeout(()=>setV(true),delay);return ()=>clearTimeout(t)},[delay]);return <div style={{opacity:v?1:0,transform:v?"translateY(0)":"translateY(18px)",transition:`all .6s cubic-bezier(.16,1,.3,1) ${delay}ms`}}>{children}</div>}
function Str({r,s=13}){const f=Math.floor(r);const h=r%1>=.3;return <span style={{color:"#F5A623",fontSize:s,letterSpacing:2}}>{"★".repeat(f)}{h?"½":""}{"☆".repeat(5-f-(h?1:0))}</span>}
