function BudgetBar({spent,total,label}){const pct=Math.min(100,Math.round(spent/total*100));const col=pct>90?"#C62828":pct>70?"#E65100":"#2D6A4F";return <div style={{marginBottom:12}}><div style={{display:"flex",justifyContent:"space-between",fontSize:11,marginBottom:4}}><span style={{fontWeight:600,color:"#333"}}>{label}</span><span style={{color:col,fontWeight:800,fontFamily:"'DM Mono',monospace"}}>{spent}€ / {total}€</span></div><div style={{height:8,background:"#f0ece6",borderRadius:6,overflow:"hidden"}}><div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${col},${col}99)`,borderRadius:6,transition:"width .6s cubic-bezier(.16,1,.3,1)"}}/></div></div>}

function AffiliateBtn({type,label,small}){const af=AFFILIATES[type];if(!af)return null;return <button onClick={e=>{e.stopPropagation();window.open(af.url,"_blank")}} style={{background:small?"none":`linear-gradient(135deg,${af.color},${af.color}cc)`,color:small?af.color:"#fff",border:small?`1.5px solid ${af.color}`:"none",borderRadius:small?10:12,padding:small?"4px 12px":"10px 18px",fontSize:small?10:12,fontWeight:700,cursor:"pointer",fontFamily:"inherit",boxShadow:small?"none":`0 3px 12px ${af.color}33`,transition:"all .15s",display:"flex",alignItems:"center",gap:6}}>{!small&&<span style={{width:18,height:18,borderRadius:4,background:"rgba(255,255,255,.2)",display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:800}}>{af.logo}</span>}{label||af.name}{!small&&<span style={{fontSize:9,opacity:.7}}>↗</span>}</button>}

