mn:{maxWidth:900,margin:"0 auto",padding:"16px 20px 110px"},
ti:{fontFamily:FF,fontSize:24,fontWeight:700,letterSpacing:"-.3px",color:"#1A1A1A"},
su:{fontSize:12,color:"#999",marginTop:4,fontWeight:500},
